import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# Define robust CUDA kernel with explicit bounds checking
matmul_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>

__global__ void matmul_kernel(const float* A, const float* B, float* C, int N) {
    const int TILE_SIZE = 32;
    __shared__ float As[TILE_SIZE][TILE_SIZE];
    __shared__ float Bs[TILE_SIZE][TILE_SIZE];

    int bx = blockIdx.x, by = blockIdx.y;
    int tx = threadIdx.x, ty = threadIdx.y;

    int row = by * TILE_SIZE + ty;
    int col = bx * TILE_SIZE + tx;

    float sum = 0.0f;

    for (int tile = 0; tile < (N + TILE_SIZE - 1) / TILE_SIZE; ++tile) {
        // SAFE LOADING with explicit bounds checking before memory access
        int a_col_idx = tile * TILE_SIZE + tx;
        int b_row_idx = tile * TILE_SIZE + ty;

        // Use explicit boolean conditions to prevent out-of-bounds reads
        bool a_inbounds = (row < N) && (a_col_idx < N);
        bool b_inbounds = (b_row_idx < N) && (col < N);

        As[ty][tx] = a_inbounds ? A[row * N + a_col_idx] : 0.0f;
        Bs[ty][tx] = b_inbounds ? B[b_row_idx * N + col] : 0.0f;

        __syncthreads();

        for (int k = 0; k < TILE_SIZE; ++k) {
            sum += As[ty][k] * Bs[k][tx];
        }

        __syncthreads();
    }

    if (row < N && col < N) {
        C[row * N + col] = sum;
    }
}

torch::Tensor matmul_cuda(torch::Tensor A, torch::Tensor B) {
    int N = A.size(0);
    // Validate inputs before kernel launch
    TORCH_CHECK(A.size(1) == N, "Matrix A must be square");
    TORCH_CHECK(B.size(0) == N && B.size(1) == N, "Matrix B must be NxN");

    auto C = torch::zeros({N, N}, A.options());

    const int TILE_SIZE = 32;
    dim3 blockDim(TILE_SIZE, TILE_SIZE);
    dim3 gridDim((N + TILE_SIZE - 1) / TILE_SIZE, (N + TILE_SIZE - 1) / TILE_SIZE);

    if (N > 0) {
        matmul_kernel<<<gridDim, blockDim>>>(
            A.data_ptr<float>(),
            B.data_ptr<float>(),
            C.data_ptr<float>(),
            N
        );
    }

    return C;
}
"""

matmul_cpp_source = "torch::Tensor matmul_cuda(torch::Tensor A, torch::Tensor B);"

# Compile the inline CUDA code
matmul_cuda = load_inline(
    name="matmul_cuda",
    cpp_sources=matmul_cpp_source,
    cuda_sources=matmul_source,
    functions=["matmul_cuda"],
    verbose=False,
    extra_cflags=["-O3"],
    extra_ldflags=["-lcublas"],
)

class ModelNew(nn.Module):
    """
    Optimized model with robust CUDA kernel for matrix multiplication
    """
    def __init__(self):
        super(ModelNew, self).__init__()
        self.matmul_cuda = matmul_cuda

    def forward(self, A: torch.Tensor, B: torch.Tensor) -> torch.Tensor:
        # Additional Python-level validation
        assert A.dim() == 2 and B.dim() == 2, "Inputs must be 2D tensors"
        assert A.size(0) == A.size(1) and B.size(0) == B.size(1), \
               "Inputs must be square matrices"
        assert A.size(0) == B.size(0), "Matrices must have same dimension"

        return self.matmul_cuda.matmul_cuda(A, B)

N = 2048

def get_inputs():
    A = torch.randn(N, N).cuda()
    B = torch.randn(N, N).cuda()
    return [A, B]

